/**
 * LLM calling utility — migrated from V1.
 *
 * Supports DeepSeek, OpenAI, and Custom API providers.
 * Includes AbortController timeout and call logging.
 */

import type { APISettings } from '../types/common';
import { encryptSettings, decryptSettings } from './api';

/** LLM message format */
export interface LLMMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

/** Call log entry */
interface CallLogEntry {
  time: string;
  model: string;
  tokens: number;
  latency: number;
  status: 'success' | 'error';
}

// In-memory call log buffer (synced to IndexedDB when available)
const callLogs: CallLogEntry[] = [];

/** Load API settings from localStorage */
export function loadAPISettings(): APISettings {
  const defaultSettings: APISettings = {
    provider: 'deepseek',
    apiKey: '',
    customBaseUrl: '',
    customModel: '',
    model: 'deepseek-chat',
    proxyUrl: '',
  };

  try {
    const encrypted = localStorage.getItem('vos-api-settings');
    if (encrypted) {
      const decrypted = decryptSettings<APISettings>(encrypted);
      if (decrypted) return { ...defaultSettings, ...decrypted };
    }
  } catch {
    console.warn('Failed to load API settings');
  }

  return defaultSettings;
}

/** Save API settings to localStorage */
export function saveAPISettings(settings: APISettings): void {
  const encrypted = encryptSettings(settings);
  localStorage.setItem('vos-api-settings', encrypted);
}

/** Log an AI call */
export function logAICall(
  model: string,
  tokens: number,
  latency: number,
  status: 'success' | 'error',
): void {
  const entry: CallLogEntry = {
    time: new Date().toLocaleString(),
    model,
    tokens,
    latency,
    status,
  };
  callLogs.push(entry);
  if (callLogs.length > 100) callLogs.shift();

  try {
    localStorage.setItem('vos-call-logs', JSON.stringify(callLogs));
  } catch {
    // localStorage full — ignore
  }
}

/**
 * Call LLM API.
 *
 * @param messages - Array of chat messages
 * @param maxTokens - Maximum tokens in response (default 2000)
 * @param short - If true, sets temperature to 0 for deterministic output
 * @returns The model's response text
 */
export async function callLLM(
  messages: LLMMessage[],
  maxTokens: number = 2000,
  short: boolean = false,
): Promise<string> {
  const s = loadAPISettings();
  const isDeepSeek = s.provider === 'deepseek' || !s.provider;

  let endpoint: string;
  let model: string;

  if (s.provider === 'openai') {
    endpoint = 'https://api.openai.com/v1/chat/completions';
    model = s.model || 'gpt-4o';
  } else if (s.provider === 'custom') {
    endpoint = (s.customBaseUrl || 'https://api.openai.com/v1') + '/chat/completions';
    model = s.customModel || 'gpt-4o-mini';
  } else {
    // DeepSeek (default)
    endpoint = 'https://api.deepseek.com/v1/chat/completions';
    model = s.model || 'deepseek-chat';
  }

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
    Authorization: 'Bearer ' + s.apiKey,
  };

  // Use CORS proxy if configured
  const proxy = s.proxyUrl || '';
  const fetchUrl = proxy ? proxy + encodeURIComponent(endpoint) : endpoint;

  const body: Record<string, unknown> = {
    model,
    messages,
    max_tokens: maxTokens,
    temperature: short ? 0 : 0.3,
  };

  // Only add response_format for non-DeepSeek providers
  if (!short && !isDeepSeek) {
    body.response_format = { type: 'json_object' };
  }

  const startTime = Date.now();
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 90000);

  let latency: number;
  let resp: Response;

  try {
    resp = await fetch(fetchUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify(body),
      signal: controller.signal,
    });
  } finally {
    clearTimeout(timeoutId);
  }

  latency = Date.now() - startTime;

  if (!resp.ok) {
    const errText = await resp.text();
    const errMsg = errText.length > 500 ? errText.substring(0, 500) + '...' : errText;
    logAICall(model, 0, latency, 'error');
    throw new Error(`API ${resp.status}: ${errMsg}`);
  }

  const data = await resp.json();
  const tokens = data.usage?.total_tokens || 0;
  logAICall(model, tokens, latency, 'success');
  return data.choices[0].message.content;
}
