/**
 * API Key encryption/decryption utilities.
 * Uses CryptoJS AES with a SHA256-derived key for secure storage.
 *
 * IMPORTANT: The encryption key derivation is FIXED to ensure compatibility
 * with previously encrypted data. The key is derived from browser fingerprint
 * (userAgent + language + screen dimensions + colorDepth).
 */

import CryptoJS from 'crypto-js';

/** Generate the encryption key from browser fingerprint */
function deriveEncryptionKey(): string {
  const seed = [
    navigator.userAgent,
    navigator.language,
    screen.width + 'x' + screen.height,
    screen.colorDepth,
  ].join('|');
  return 'voc-' + CryptoJS.SHA256(seed).toString().substring(0, 32);
}

let cachedKey: string | null = null;

function getEncryptionKey(): string {
  if (!cachedKey) {
    cachedKey = deriveEncryptionKey();
  }
  return cachedKey;
}

/**
 * Encrypt settings data as an AES-encrypted JSON string.
 * Falls back to plaintext JSON if CryptoJS is unavailable.
 */
export function encryptSettings<T>(data: T): string {
  try {
    if (typeof CryptoJS !== 'undefined') {
      return CryptoJS.AES.encrypt(JSON.stringify(data), getEncryptionKey()).toString();
    }
    console.warn('CryptoJS not available, saving as plaintext');
    return JSON.stringify(data);
  } catch (err) {
    console.error('Encryption failed:', err);
    return JSON.stringify(data);
  }
}

/**
 * Decrypt settings from an AES-encrypted string.
 * Falls back to parsing as plaintext JSON.
 */
export function decryptSettings<T>(encrypted: string): T | null {
  try {
    if (typeof CryptoJS !== 'undefined') {
      const bytes = CryptoJS.AES.decrypt(encrypted, getEncryptionKey());
      const decrypted = bytes.toString(CryptoJS.enc.Utf8);
      if (decrypted) {
        return JSON.parse(decrypted) as T;
      }
    }
    // Fallback: try parsing as plaintext
    return JSON.parse(encrypted) as T;
  } catch (err) {
    console.error('Decryption failed:', err);
    return null;
  }
}
