/**
 * AI Workbench Page — Full implementation.
 *
 * Features:
 * - Agent dependency flow visualization (4-layer, 10 agents)
 * - Three run modes: Full chain / Insights only / Strategy only
 * - Real-time progress with spinner, ✅/❌ icons, log stream
 * - Data overview: comment count, unanalyzed count, confirmed insights
 * - Single comment test button
 */

import React, { useState, useCallback, useEffect } from 'react';
import {
  Box,
  Typography,
  Button,
  ButtonGroup,
  Card,
  CardContent,
  Chip,
  LinearProgress,
  Paper,
  TextField,
  IconButton,
  Tooltip,
  Divider,
  Alert,
} from '@mui/material';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import ScienceIcon from '@mui/icons-material/Science';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ErrorIcon from '@mui/icons-material/Error';
import HourglassEmptyIcon from '@mui/icons-material/HourglassEmpty';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import InsightsIcon from '@mui/icons-material/Insights';
import LightbulbIcon from '@mui/icons-material/Lightbulb';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useCommentStore } from '@/shared/stores/commentStore';
import { useInsightStore } from '@/shared/stores/insightStore';
import { countCommentsByBrand } from '@/shared/db/comment.db';
import { db } from '@/shared/db/db';
import type { Comment } from '@/shared/types/comment';
import {
  AGENTS,
  ALL_AGENTS_ORDERED,
  STRATEGY_AGENTS,
  AGENT_CHAIN,
  runAgentChain,
  runSingleAgent,
  testSingleComment,
  type AgentRunStatus,
  type PipelineProgress,
  type RunMode,
  MODE_START_AGENTS,
} from './AIAgentChain';

// ─── Agent Card ──────────────────────────────────────────────────────

const AGENT_ICONS: Record<string, string> = {
  comments: '💬', content: '📺', demands: '🗺️', barriers: '🛡️',
  competitors: '🎯', xhs: '📕', douyin: '🎵', lab: '🧪',
  dashboard: '🏠', reviews: '📊',
};

interface AgentCardProps {
  agentId: string;
  status: AgentRunStatus | undefined;
}

const AgentCard: React.FC<AgentCardProps> = ({ agentId, status }) => {
  const agent = AGENTS.find((a, i) => {
    const names = ALL_AGENTS_ORDERED;
    return names[i] === agentId;
  });

  const icon = AGENT_ICONS[agentId] ?? '🤖';
  const name = agent?.name ?? agentId;
  const skill = agent?.skill ?? '';
  const isRunning = status?.status === 'running';
  const isDone = status?.status === 'done';
  const isError = status?.status === 'error';

  return (
    <Card
      sx={{
        minWidth: 160,
        flex: 1,
        border: isRunning
          ? '2px solid'
          : isDone
            ? '1px solid'
            : isError
              ? '1px solid'
              : '1px solid',
        borderColor: isRunning
          ? 'primary.main'
          : isDone
            ? 'success.main'
            : isError
              ? 'error.main'
              : 'divider',
        bgcolor: isRunning ? 'action.hover' : 'background.paper',
        transition: 'all 0.3s ease',
        opacity: status && !isRunning && !isDone && !isError ? 0.6 : 1,
      }}
    >
      <CardContent sx={{ p: 1.5, '&:last-child': { pb: 1.5 } }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5, mb: 0.5 }}>
          <Typography variant="h5" component="span">
            {icon}
          </Typography>
          <Typography variant="caption" fontWeight={700} noWrap>
            {name.replace('Agent', '')}
          </Typography>
          {isRunning && (
            <Box
              component="span"
              sx={{
                ml: 'auto',
                width: 16,
                height: 16,
                borderRadius: '50%',
                border: '2px solid',
                borderColor: 'primary.main',
                borderTopColor: 'transparent',
                animation: 'spin 0.8s linear infinite',
                '@keyframes spin': {
                  '0%': { transform: 'rotate(0deg)' },
                  '100%': { transform: 'rotate(360deg)' },
                },
              }}
            />
          )}
          {isDone && <CheckCircleIcon sx={{ ml: 'auto', fontSize: 18, color: 'success.main' }} />}
          {isError && <ErrorIcon sx={{ ml: 'auto', fontSize: 18, color: 'error.main' }} />}
        </Box>
        <Typography variant="caption" color="text.secondary" sx={{ fontSize: 10 }}>
          {skill}
        </Typography>
        {isError && status?.errorMsg && (
          <Typography variant="caption" color="error.main" sx={{ fontSize: 10, mt: 0.5, display: 'block' }}>
            {status.errorMsg.substring(0, 50)}
          </Typography>
        )}
      </CardContent>
    </Card>
  );
};

// ─── Main Page ───────────────────────────────────────────────────────

const AIWorkbenchPage: React.FC = () => {
  const currentBrandId = useBrandStore((s) => s.currentBrandId);
  const brand = useBrandStore((s) => s.getCurrentBrand());
  const loadComments = useCommentStore((s) => s.loadComments);
  const comments = useCommentStore((s) => s.comments);
  const loadInsights = useInsightStore((s) => s.loadInsights);
  const insights = useInsightStore((s) => s.insights);

  const [statuses, setStatuses] = useState<Record<string, AgentRunStatus>>({});
  const [logs, setLogs] = useState<string[]>([]);
  const [isRunning, setIsRunning] = useState(false);
  const [mode, setMode] = useState<RunMode>('full');

  // Test single comment
  const [testCommentId, setTestCommentId] = useState('');
  const [testResult, setTestResult] = useState('');
  const [testLoading, setTestLoading] = useState(false);

  // Stats
  const [totalComments, setTotalComments] = useState(0);
  const [unanalyzedCount, setUnanalyzedCount] = useState(0);

  const brandId = currentBrandId ?? '';

  // Load stats
  useEffect(() => {
    if (!brandId) return;
    countCommentsByBrand(brandId).then(setTotalComments);
    loadComments(brandId);
    loadInsights(brandId);
  }, [brandId, loadComments, loadInsights]);

  useEffect(() => {
    setUnanalyzedCount(comments.filter((c) => !c.isAnalyzed).length);
  }, [comments]);

  const confirmedCount = insights.filter((i) => i.reviewStatus === 'confirmed').length;

  // ─── Run Pipeline ───
  const handleRun = useCallback(async () => {
    if (!brandId || isRunning) return;

    setIsRunning(true);
    setStatuses({});
    setLogs([]);

    try {
      const startId = MODE_START_AGENTS[mode][0];
      await runAgentChain(startId, brandId, (progress: PipelineProgress) => {
        setStatuses({ ...progress.statuses });
        setLogs([...progress.logs]);
      });

      // Reload data after analysis
      await loadComments(brandId);
      await loadInsights(brandId);
      const total = await countCommentsByBrand(brandId);
      setTotalComments(total);
    } catch (e) {
      setLogs((prev) => [
        ...prev,
        `❌ 管线执行异常: ${e instanceof Error ? e.message : String(e)}`,
      ]);
    } finally {
      setIsRunning(false);
    }
  }, [brandId, isRunning, mode, loadComments, loadInsights]);

  // ─── Single Agent Test ───
  const handleRunSingle = useCallback(
    async (agentId: string) => {
      if (!brandId || isRunning) return;
      setIsRunning(true);
      setStatuses({});
      setLogs([]);

      try {
        const msg = await runSingleAgent(agentId, brandId);
        setStatuses({
          [agentId]: { agentId, status: 'done', resultMsg: msg },
        });
        setLogs([`[单Agent] ${AGENT_ICONS[agentId] ?? '🤖'} ${agentId}: ${msg}`]);
        await loadComments(brandId);
        await loadInsights(brandId);
      } catch (e) {
        setStatuses({
          [agentId]: {
            agentId,
            status: 'error',
            errorMsg: e instanceof Error ? e.message : String(e),
          },
        });
      } finally {
        setIsRunning(false);
      }
    },
    [brandId, isRunning, loadComments, loadInsights],
  );

  // ─── Test Single Comment ───
  const handleTestComment = useCallback(async () => {
    if (!brandId || !testCommentId.trim()) return;
    const targetComment = comments.find((c) => c.id === Number(testCommentId.trim()));
    if (!targetComment) {
      setTestResult('❌ 未找到该评论 ID');
      return;
    }
    setTestLoading(true);
    setTestResult('');
    try {
      const result = await testSingleComment(targetComment, brandId);
      setTestResult(result);
    } catch (e) {
      setTestResult(`❌ 测试失败: ${e instanceof Error ? e.message : String(e)}`);
    } finally {
      setTestLoading(false);
    }
  }, [brandId, testCommentId, comments]);

  // ─── Agent Layers (for visual layout) ───
  const agentLayers: string[][] = [
    ['comments'],
    ['content'],
    ['demands', 'barriers', 'competitors'],
    ['xhs', 'douyin'],
    ['lab'],
    ['dashboard'],
    ['reviews'],
  ];

  // Filter layers for strategy-only mode
  const displayLayers = mode === 'strategy-only'
    ? agentLayers.filter((layer) =>
        layer.some((id) => STRATEGY_AGENTS.includes(id)),
      )
    : agentLayers;

  return (
    <Box sx={{ height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Header */}
      <Box
        sx={{
          p: 2,
          borderBottom: '1px solid',
          borderColor: 'divider',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          flexWrap: 'wrap',
          gap: 1,
        }}
      >
        <Box>
          <Typography variant="h6" fontWeight={700}>
            🤖 AI 工作台
          </Typography>
          <Typography variant="body2" color="text.secondary">
            {brand?.name ?? '未选择品牌'} · 评论 {totalComments} 条 · 未分析 {unanalyzedCount} 条 · 已确认洞察 {confirmedCount} 条
          </Typography>
        </Box>

        <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
          <ButtonGroup size="small">
            <Button
              variant={mode === 'full' ? 'contained' : 'outlined'}
              onClick={() => setMode('full')}
            >
              🚀 全链路
            </Button>
            <Button
              variant={mode === 'insights-only' ? 'contained' : 'outlined'}
              onClick={() => setMode('insights-only')}
            >
              🔍 仅洞察
            </Button>
            <Button
              variant={mode === 'strategy-only' ? 'contained' : 'outlined'}
              onClick={() => setMode('strategy-only')}
            >
              🎯 仅策略
            </Button>
          </ButtonGroup>

          <Button
            variant="contained"
            startIcon={
              isRunning ? (
                <Box
                  component="span"
                  sx={{
                    width: 18,
                    height: 18,
                    borderRadius: '50%',
                    border: '2px solid',
                    borderColor: 'inherit',
                    borderTopColor: 'transparent',
                    animation: 'spin 0.8s linear infinite',
                    '@keyframes spin': {
                      '0%': { transform: 'rotate(0deg)' },
                      '100%': { transform: 'rotate(360deg)' },
                    },
                  }}
                />
              ) : (
                <PlayArrowIcon />
              )
            }
            onClick={handleRun}
            disabled={isRunning || !brandId}
            color="primary"
          >
            {isRunning ? '运行中...' : `运行 ${mode === 'full' ? '全链路' : mode === 'insights-only' ? '洞察' : '策略'}`}
          </Button>
        </Box>
      </Box>

      {/* Agent Flow */}
      <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
        {displayLayers.map((layer, layerIdx) => (
          <Box key={layerIdx} sx={{ mb: 2 }}>
            {/* Layer label */}
            <Typography
              variant="caption"
              color="text.secondary"
              sx={{ mb: 0.5, display: 'block', fontWeight: 600, textTransform: 'uppercase' }}
            >
              Layer {layerIdx + 1}
            </Typography>
            <Box sx={{ display: 'flex', gap: 1.5, flexWrap: 'wrap' }}>
              {layer.map((agentId) => (
                <Box key={agentId} sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                  <AgentCard agentId={agentId} status={statuses[agentId]} />
                  {/* Single agent run button */}
                  {!isRunning && (
                    <Tooltip title={`单独运行 ${AGENT_ICONS[agentId]} Agent`}>
                      <IconButton
                        size="small"
                        onClick={() => handleRunSingle(agentId)}
                        sx={{ mt: 0.5 }}
                      >
                        <ScienceIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                  )}
                </Box>
              ))}
            </Box>
            {/* Arrow between layers */}
            {layerIdx < displayLayers.length - 1 && (
              <Box sx={{ textAlign: 'center', my: 0.5 }}>
                <Typography variant="caption" color="text.disabled">
                  ↓
                </Typography>
              </Box>
            )}
          </Box>
        ))}

        {/* Progress bar */}
        {isRunning && (
          <Box sx={{ mt: 2 }}>
            <LinearProgress />
            <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5, display: 'block' }}>
              当前: {Object.entries(statuses).find(([, s]) => s.status === 'running')?.[0] ?? '初始化...'}
            </Typography>
          </Box>
        )}
      </Box>

      {/* Log Stream + Test Panel */}
      <Box
        sx={{
          borderTop: '1px solid',
          borderColor: 'divider',
          height: 240,
          display: 'flex',
          flexDirection: 'row',
        }}
      >
        {/* Log Stream */}
        <Box
          sx={{
            flex: 1,
            borderRight: '1px solid',
            borderColor: 'divider',
            display: 'flex',
            flexDirection: 'column',
          }}
        >
          <Box
            sx={{
              px: 2,
              py: 1,
              borderBottom: '1px solid',
              borderColor: 'divider',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
            }}
          >
            <Typography variant="caption" fontWeight={700}>
              📋 运行日志
            </Typography>
            <Button
              size="small"
              variant="text"
              onClick={() => setLogs([])}
              sx={{ minWidth: 'auto', fontSize: 11 }}
            >
              清空
            </Button>
          </Box>
          <Box
            sx={{
              flex: 1,
              overflow: 'auto',
              p: 1,
              fontFamily: 'monospace',
              fontSize: 11,
              lineHeight: 1.6,
              bgcolor: 'grey.900',
              color: '#e0e0e0',
            }}
          >
            {logs.length === 0 ? (
              <Typography variant="caption" sx={{ color: 'grey.500', fontFamily: 'monospace' }}>
                等待运行...
              </Typography>
            ) : (
              logs.map((log, i) => (
                <Box
                  key={i}
                  sx={{
                    color: log.includes('❌')
                      ? '#f87171'
                      : log.includes('✅')
                        ? '#4ade80'
                        : log.includes('⏭️')
                          ? '#fbbf24'
                          : '#e0e0e0',
                  }}
                >
                  {log}
                </Box>
              ))
            )}
          </Box>
        </Box>

        {/* Test single comment */}
        <Box sx={{ width: 320, display: 'flex', flexDirection: 'column' }}>
          <Box
            sx={{
              px: 2,
              py: 1,
              borderBottom: '1px solid',
              borderColor: 'divider',
            }}
          >
            <Typography variant="caption" fontWeight={700}>
              🧪 单条测试
            </Typography>
          </Box>
          <Box sx={{ p: 1.5, display: 'flex', flexDirection: 'column', gap: 1, flex: 1 }}>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <TextField
                size="small"
                placeholder="评论 ID"
                value={testCommentId}
                onChange={(e) => setTestCommentId(e.target.value)}
                sx={{ flex: 1 }}
                disabled={testLoading}
              />
              <Button
                size="small"
                variant="outlined"
                onClick={handleTestComment}
                disabled={testLoading || !testCommentId.trim()}
              >
                {testLoading ? '...' : '测试'}
              </Button>
            </Box>
            {testResult && (
              <Paper
                variant="outlined"
                sx={{
                  flex: 1,
                  p: 1,
                  overflow: 'auto',
                  fontFamily: 'monospace',
                  fontSize: 10,
                  bgcolor: 'grey.900',
                  color: '#e0e0e0',
                  whiteSpace: 'pre-wrap',
                  wordBreak: 'break-all',
                }}
              >
                {testResult}
              </Paper>
            )}
            {!testResult && (
              <Typography variant="caption" color="text.secondary">
                输入评论 ID，测试单条评论的 AI 分析结果
              </Typography>
            )}
          </Box>
        </Box>
      </Box>
    </Box>
  );
};

export default AIWorkbenchPage;
