/** Helper: create a new review log entry */
function newLog(action: ReviewLog['action'], operator: string = 'AI System', changes?: string): ReviewLog {
  return {
    action,
    timestamp: new Date().toISOString(),
    operator,
    changes: changes ?? null,
  };
}

/** Helper: clean markdown JSON from LLM response */
function parseJSONResponse(data: string): Record<string, unknown> {
  let text = data;
  try {
    if (text.includes('```json')) {
      text = text.split('```json')[1].split('```')[0].trim();
    } else if (text.includes('```')) {
      text = text.split('```')[1].split('```')[0].trim();
    }
  } catch {
    // Use raw text
  }
  return JSON.parse(text);
}

