/** Agent name → Agent Definition map */
const AGENT_MAP: Record<string, AgentDefinition> = {};
AGENTS.forEach((a) => {
  const key = AGENTS.indexOf(a);
  const names = [
    'comments', 'content', 'demands', 'barriers', 'competitors',
    'xhs', 'douyin', 'lab', 'dashboard', 'reviews',
  ];
  AGENT_MAP[names[key]] = a;
});

/**
 * Build agent context from DexieDB for a given brand.
 * Only includes comments where isAnalyzed === false (incremental analysis).
 */
export async function buildAgentContext(brandId: string): Promise<AgentContext> {
  const brand = await db.brands.get(brandId);
  const allComments = await db.comments.where({ brandId }).toArray();
  const insights = await db.insights.where({ brandId }).toArray();
  const demands: Demand[] = insights.filter(
    (i) => i.type === 'demand',
  ) as Demand[];
  const barriers: Barrier[] = insights.filter(
    (i) => i.type === 'barrier',
  ) as Barrier[];
  const competitorInsights: CompetitorInsight[] = insights.filter(
    (i) => i.type === 'competitor',
  ) as CompetitorInsight[];

  const strategyCards: StrategyCard[] = await db.strategyCards
    .where({ brandId })
    .toArray();

  return {
    brandId,
    comments: allComments,
    demands,
    barriers,
    competitorInsights,
    strategyCards,
    brandConfig: brand?.config ?? {
      products: [],
      brandStory: '',
      visualStyle: '',
      tone: '',
      keywords: { brandWords: [], categoryWords: [], sceneWords: [], audienceWords: [] },
      contentGuidelines: { do: [], dont: [] },
    },
    competitors: brand?.competitors ?? [],
  };
}

/**
 * Run a single agent.
 * Returns the result message string.
 */
export async function runSingleAgent(
  agentId: string,
  brandId: string,
): Promise<string> {
  const agent = AGENT_MAP[agentId];
  if (!agent) throw new Error(`Unknown agent: ${agentId}`);

  const ctx = await buildAgentContext(brandId);
  const prompt = agent.buildPrompt(ctx);
  if (!prompt) return '⏭️ 当前没有可分析的数据，已跳过';

  const resp = await callLLM([{ role: 'user', content: prompt }], 3000);
  const msg = await agent.applyResult(resp, brandId);
  return msg;
}

/**
 * Run the full agent chain starting from a given agent.
 * Supports progress callback.
 */
export async function runAgentChain(
  startAgentId: string,
  brandId: string,
  onProgress?: (progress: PipelineProgress) => void,
  agentChain?: Record<string, string[]>,
): Promise<PipelineProgress> {
  const chain = agentChain ?? AGENT_CHAIN;

  const progress: PipelineProgress = {
    currentAgent: startAgentId,
    statuses: {},
    logs: [],
  };

  const addLog = (msg: string) => {
    progress.logs.push(`[${new Date().toLocaleTimeString()}] ${msg}`);
    onProgress?.({ ...progress, logs: [...progress.logs] });
  };

  const setStatus = (agentId: string, status: AgentRunStatus['status'], resultMsg?: string, errorMsg?: string) => {
    progress.statuses[agentId] = {
      agentId,
      status,
      resultMsg: resultMsg ?? progress.statuses[agentId]?.resultMsg,
      errorMsg: errorMsg ?? progress.statuses[agentId]?.errorMsg,
    };
  };

  const runOne = async (id: string): Promise<void> => {
    const agent = AGENT_MAP[id];
    if (!agent) return;
    if (progress.statuses[id]?.status === 'running') return;

    progress.currentAgent = id;
    setStatus(id, 'running');
    addLog(`${agent.icon} ${agent.name} 开始运行...`);

    try {
      const msg = await runSingleAgent(id, brandId);
      setStatus(id, 'done', msg);
      addLog(`${agent.icon} ${agent.name}: ${msg}`);
    } catch (e) {
      const errMsg = e instanceof Error ? e.message : String(e);
      setStatus(id, 'error', undefined, errMsg);
      addLog(`❌ ${agent.icon} ${agent.name} 失败: ${errMsg}`);
      // Continue chain on error — don't stop subsequent agents
    }

    onProgress?.(progress);

    // Run downstream agents
    if (chain[id]) {
      for (const nextId of chain[id]) {
        await runOne(nextId);
      }
    }
  };

  await runOne(startAgentId);
  return progress;
}

/**
 * Run analysis pipeline for a specific mode.
 */
export async function runAnalysisPipeline(
  brandId: string,
  mode: RunMode,
  onProgress?: (progress: PipelineProgress) => void,
): Promise<PipelineProgress> {
  const startAgents = MODE_START_AGENTS[mode];

  const progress: PipelineProgress = {
    currentAgent: startAgents[0],
    statuses: {},
    logs: [],
  };

  const addLog = (msg: string) => {
    progress.logs.push(`[${new Date().toLocaleTimeString()}] ${msg}`);
    onProgress?.(progress);
  };

  const setStatus = (agentId: string, status: AgentRunStatus['status'], resultMsg?: string, errorMsg?: string) => {
    progress.statuses[agentId] = {
      agentId,
      status,
      resultMsg: resultMsg ?? progress.statuses[agentId]?.resultMsg,
      errorMsg: errorMsg ?? progress.statuses[agentId]?.errorMsg,
    };
  };

  addLog(`🚀 启动分析管线: ${mode}`);

  for (const startId of startAgents) {
    const chainResult = await runAgentChain(startId, brandId, (p) => {
      Object.assign(progress.statuses, p.statuses);
      progress.currentAgent = p.currentAgent;
      progress.logs = [...p.logs];
      onProgress?.(progress);
    });

    Object.assign(progress.statuses, chainResult.statuses);
    progress.logs = [...chainResult.logs];
  }

  addLog('✅ 分析管线执行完毕');
  return progress;
}

/**
 * Test single comment analysis.
 * Analyzes one comment using the comments agent and returns the result.
 */
export async function testSingleComment(
  comment: Comment,
  brandId: string,
): Promise<string> {
  const ctx = await buildAgentContext(brandId);
  ctx.comments = [comment];

  const agent = AGENT_MAP['comments'];
  if (!agent) throw new Error('Comments agent not found');

  const prompt = agent.buildPrompt(ctx);
  if (!prompt) throw new Error('Failed to build prompt');

  const resp = await callLLM([{ role: 'user', content: prompt }], 2000);
  const parsed = parseJSONResponse(resp);
  return JSON.stringify(parsed, null, 2);
}
